script:
frappe.ui.form.on('Hall Allocation', {
    student_group: function(frm) {
        if (!frm.doc.student_group) {
            frm.clear_table('students');
            frm.refresh_field('students');
            return;
        }
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Student Group',
                name: frm.doc.student_group
            },
            callback: function(r) {
                if (r.message) {
                    frm.clear_table('students');
                    (r.message.students || []).forEach(function(row) {
                        if (row.active) {
                            var child = frm.add_child('students');
                            child.student = row.student;
                            child.student_name = row.student_name;
                            child.roll_no = row.group_roll_number;
                        }
                    });
                    frm.refresh_field('students');
                    frappe.show_alert({
                        message: 'Fetched ' + frm.doc.students.length + ' students from ' + frm.doc.student_group,
                        indicator: 'green'
                    });
                }
            }
        });
    }
});
